Many developers implement minimal logging that fails to capture the critical details needed for security investigations. When breaches occur, incomplete audit trails make it nearly impossible to determine what data was accessed, by whom, and when.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

app.use(express.json());

// Minimal logging - common anti-pattern
app.post('/admin/users/:id/update', async (req, res) => {
  try {
    const userId = req.params.id;
    const updates = req.body;

    // Only logs that something happened - no details
    console.log('User updated');

    await db.users.update(userId, updates);
    res.json({ success: true });
  } catch (error) {
    console.log('Error occurred');
    res.status(500).json({ error: 'Update failed' });
  }
});

app.delete('/admin/users/:id', async (req, res) => {
  try {
    const userId = req.params.id;

    // No logging at all for critical operation!
    await db.users.delete(userId);
    res.json({ success: true });
  } catch (error) {
    res.status(500).json({ error: 'Delete failed' });
  }
});

app.get('/admin/users/:id/sensitive-data', async (req, res) => {
  const user = await db.users.findById(req.params.id);
  // No audit of sensitive data access
  res.json(user);
});
```

**Attack Scenario**:
```text
1. Attacker gains admin access via credential stuffing
2. Exports all customer PII over several sessions
3. Deletes evidence by removing certain user records
4. Breach discovered 3 weeks later when customers report fraud
5. Forensic investigation fails due to lack of audit trails
```

**Why This Is Dangerous**:
- No record of WHO performed actions (missing actor identification)
- No record of WHAT was accessed or modified (missing action details)
- No record of WHEN events occurred (missing timestamps)
- No logging of sensitive data access (compliance violation)
- Console.log is not persistent and easily lost
- Cannot detect anomalous patterns or unauthorized access

**SECURE VERSION**:

```javascript
const express = require('express');
const winston = require('winston');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());

// Structured audit logger with persistent storage
const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp({ format: 'ISO' }),
    winston.format.json()
  ),
  defaultMeta: { service: 'admin-panel' },
  transports: [
    new winston.transports.File({ filename: 'audit.log' }),
    new winston.transports.Console()
  ]
});

// Audit trail middleware
function createAuditEntry(action, resourceType) {
  return (req, res, next) => {
    req.auditId = uuidv4();
    req.auditContext = {
      auditId: req.auditId,
      action: action,
      resourceType: resourceType,
      resourceId: req.params.id,
      actorId: req.user?.id,
      actorEmail: req.user?.email,
      actorRole: req.user?.role,
      ipAddress: req.ip,
      userAgent: req.get('User-Agent'),
      sessionId: req.session?.id,
      timestamp: new Date().toISOString()
    };

    // Log action initiation
    auditLogger.info('Action initiated', req.auditContext);
    next();
  };
}

app.post('/admin/users/:id/update',
  createAuditEntry('USER_UPDATE', 'user'),
  async (req, res) => {
    const { auditContext } = req;

    try {
      const userId = req.params.id;
      const updates = req.body;

      // Get before state for audit
      const beforeState = await db.users.findById(userId);

      await db.users.update(userId, updates);

      // Get after state
      const afterState = await db.users.findById(userId);

      // Log successful action with full context
      auditLogger.info('Action completed', {
        ...auditContext,
        status: 'success',
        changes: {
          before: sanitizeForAudit(beforeState),
          after: sanitizeForAudit(afterState),
          modifiedFields: Object.keys(updates)
        }
      });

      res.json({ success: true });
    } catch (error) {
      auditLogger.error('Action failed', {
        ...auditContext,
        status: 'failure',
        errorMessage: error.message,
        errorCode: error.code
      });
      res.status(500).json({ error: 'Update failed' });
    }
  }
);

// Sanitize sensitive data before logging
function sanitizeForAudit(data) {
  if (!data) return null;
  const sanitized = { ...data };
  const sensitiveFields = ['password', 'ssn', 'creditCard', 'apiKey'];
  sensitiveFields.forEach(field => {
    if (sanitized[field]) sanitized[field] = '[REDACTED]';
  });
  return sanitized;
}
```

**Key Security Controls**:
- **Actor Identification**: Every action records who performed it (user ID, email, role, IP, session)
- **Action Details**: Records what was done, to which resource, with before/after states
- **Immutable Timestamps**: ISO 8601 timestamps for forensic timeline reconstruction
- **Correlation IDs**: UUID links related log entries for complex operations
- **Sensitive Data Redaction**: Prevents logging of passwords/PII while maintaining audit value
- **Persistent Storage**: File-based logging survives process restarts

Excellent questions. Production audit systems need tamper-evident logs, efficient bulk operation tracking, and asynchronous processing to maintain performance. Here's a comprehensive solution:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const winston = require('winston');
const crypto = require('crypto');
const { v4: uuidv4 } = require('uuid');
const Redis = require('ioredis');
const { Kafka } = require('kafkajs');

const app = express();
app.use(express.json());

// Redis for high-performance async queue
const redis = new Redis(process.env.REDIS_URL);

// Kafka for durable, distributed audit log streaming
const kafka = new Kafka({
  clientId: 'audit-service',
  brokers: process.env.KAFKA_BROKERS.split(',')
});
const producer = kafka.producer();

// Hash chain for tamper-evident logging
class TamperEvidentAuditLogger {
  constructor() {
    this.lastHash = process.env.AUDIT_GENESIS_HASH || 'genesis';
    this.sequence = 0;
  }

  async createEntry(auditData) {
    this.sequence++;

    const entry = {
      ...auditData,
      sequence: this.sequence,
      previousHash: this.lastHash,
      timestamp: new Date().toISOString(),
      nodeId: process.env.NODE_ID || 'node-1'
    };

    // Create cryptographic hash of entire entry
    const entryString = JSON.stringify(entry);
    const currentHash = crypto
      .createHash('sha256')
      .update(entryString)
      .digest('hex');

    entry.hash = currentHash;
    this.lastHash = currentHash;

    // Sign with server private key for non-repudiation
    if (process.env.AUDIT_PRIVATE_KEY) {
      const sign = crypto.createSign('RSA-SHA256');
      sign.update(entryString);
      entry.signature = sign.sign(process.env.AUDIT_PRIVATE_KEY, 'base64');
    }

    return entry;
  }

  verifyChain(entries) {
    for (let i = 1; i < entries.length; i++) {
      const prev = entries[i - 1];
      const curr = entries[i];

      if (curr.previousHash !== prev.hash) {
        return { valid: false, brokenAt: i, message: 'Hash chain broken' };
      }

      // Verify hash of entry
      const { hash, signature, ...entryWithoutHash } = curr;
      const expectedHash = crypto
        .createHash('sha256')
        .update(JSON.stringify(entryWithoutHash))
        .digest('hex');

      if (hash !== expectedHash) {
        return { valid: false, brokenAt: i, message: 'Entry hash mismatch' };
      }
    }
    return { valid: true };
  }
}

const auditLogger = new TamperEvidentAuditLogger();

// Async audit queue for performance
class AsyncAuditQueue {
  constructor() {
    this.buffer = [];
    this.flushInterval = setInterval(() => this.flush(), 1000);
    this.maxBufferSize = 100;
  }

  async enqueue(auditData) {
    const entry = await auditLogger.createEntry(auditData);
    this.buffer.push(entry);

    // Immediate flush for critical actions
    if (auditData.priority === 'critical' || this.buffer.length >= this.maxBufferSize) {
      await this.flush();
    }

    return entry.hash;
  }

  async flush() {
    if (this.buffer.length === 0) return;

    const entries = [...this.buffer];
    this.buffer = [];

    try {
      // Write to multiple destinations for redundancy
      await Promise.all([
        // Primary: Kafka for distributed processing
        producer.send({
          topic: 'audit-events',
          messages: entries.map(e => ({
            key: e.auditId,
            value: JSON.stringify(e),
            headers: { priority: e.priority || 'normal' }
          }))
        }),

        // Secondary: Redis for fast querying
        redis.pipeline(
          entries.map(e => [
            'ZADD',
            `audit:${e.resourceType}:${e.resourceId}`,
            Date.parse(e.timestamp),
            JSON.stringify(e)
          ])
        ).exec(),

        // Write-ahead log for crash recovery
        this.writeToWAL(entries)
      ]);
    } catch (error) {
      // Re-queue failed entries
      this.buffer = [...entries, ...this.buffer];
      console.error('Audit flush failed, entries re-queued:', error);
    }
  }

  async writeToWAL(entries) {
    const fs = require('fs').promises;
    const walPath = `/var/log/audit/wal-${Date.now()}.json`;
    await fs.writeFile(walPath, JSON.stringify(entries), { flag: 'wx' });
  }
}

const auditQueue = new AsyncAuditQueue();

// Bulk operation auditing middleware
function auditBulkOperation(action, resourceType) {
  return async (req, res, next) => {
    const batchId = uuidv4();
    const resourceIds = req.body.ids || [];

    req.auditContext = {
      batchId,
      action,
      resourceType,
      resourceCount: resourceIds.length,
      actorId: req.user?.id,
      actorEmail: req.user?.email,
      actorRole: req.user?.role,
      ipAddress: req.ip,
      userAgent: req.get('User-Agent'),
      sessionId: req.session?.id,
      priority: resourceIds.length > 10 ? 'high' : 'normal'
    };

    // Log batch initiation
    await auditQueue.enqueue({
      auditId: uuidv4(),
      ...req.auditContext,
      eventType: 'BATCH_INITIATED',
      resourceIds: resourceIds
    });

    // Track individual items
    req.auditResults = [];

    next();
  };
}

// Bulk delete with comprehensive auditing
app.post('/admin/users/bulk-delete',
  auditBulkOperation('BULK_DELETE', 'user'),
  async (req, res) => {
    const { batchId } = req.auditContext;
    const userIds = req.body.ids;
    const results = { succeeded: [], failed: [] };

    // Get all user data BEFORE deletion for audit
    const usersBeforeDelete = await Promise.all(
      userIds.map(id => db.users.findById(id).catch(() => null))
    );

    for (let i = 0; i < userIds.length; i++) {
      const userId = userIds[i];
      const userData = usersBeforeDelete[i];

      try {
        await db.users.delete(userId);
        results.succeeded.push(userId);

        // Audit individual deletion within batch
        await auditQueue.enqueue({
          auditId: uuidv4(),
          batchId,
          action: 'DELETE',
          resourceType: 'user',
          resourceId: userId,
          eventType: 'ITEM_PROCESSED',
          status: 'success',
          actorId: req.user?.id,
          deletedData: sanitizeForAudit(userData),
          priority: 'critical' // Deletions are always critical
        });
      } catch (error) {
        results.failed.push({ id: userId, error: error.message });

        await auditQueue.enqueue({
          auditId: uuidv4(),
          batchId,
          action: 'DELETE',
          resourceType: 'user',
          resourceId: userId,
          eventType: 'ITEM_PROCESSED',
          status: 'failure',
          actorId: req.user?.id,
          errorMessage: error.message,
          priority: 'high'
        });
      }
    }

    // Log batch completion
    await auditQueue.enqueue({
      auditId: uuidv4(),
      ...req.auditContext,
      eventType: 'BATCH_COMPLETED',
      summary: {
        total: userIds.length,
        succeeded: results.succeeded.length,
        failed: results.failed.length
      },
      priority: 'critical'
    });

    res.json(results);
  }
);

// Sensitive data access with mandatory audit
app.get('/admin/users/:id/pii',
  async (req, res) => {
    const auditId = uuidv4();
    const userId = req.params.id;

    // Pre-access audit (logged BEFORE data access)
    await auditQueue.enqueue({
      auditId,
      action: 'VIEW_PII',
      resourceType: 'user_pii',
      resourceId: userId,
      actorId: req.user?.id,
      actorEmail: req.user?.email,
      ipAddress: req.ip,
      eventType: 'SENSITIVE_ACCESS',
      accessJustification: req.headers['x-access-justification'] || 'none_provided',
      priority: 'critical'
    });

    try {
      const user = await db.users.findById(userId);

      // Post-access audit with data fingerprint
      await auditQueue.enqueue({
        auditId,
        action: 'VIEW_PII_COMPLETED',
        resourceType: 'user_pii',
        resourceId: userId,
        actorId: req.user?.id,
        eventType: 'SENSITIVE_ACCESS_COMPLETE',
        dataFingerprint: crypto
          .createHash('sha256')
          .update(JSON.stringify(user))
          .digest('hex'),
        fieldsAccessed: Object.keys(user),
        priority: 'critical'
      });

      res.json(user);
    } catch (error) {
      await auditQueue.enqueue({
        auditId,
        action: 'VIEW_PII_FAILED',
        resourceType: 'user_pii',
        resourceId: userId,
        actorId: req.user?.id,
        eventType: 'SENSITIVE_ACCESS_ERROR',
        errorMessage: error.message,
        priority: 'critical'
      });
      res.status(500).json({ error: 'Access failed' });
    }
  }
);

// Audit log integrity check endpoint
app.get('/admin/audit/verify',
  async (req, res) => {
    const { resourceType, resourceId, startDate, endDate } = req.query;

    const entries = await redis.zrangebyscore(
      `audit:${resourceType}:${resourceId}`,
      Date.parse(startDate),
      Date.parse(endDate)
    ).then(results => results.map(JSON.parse));

    const verification = auditLogger.verifyChain(entries);

    // Log the verification attempt itself
    await auditQueue.enqueue({
      auditId: uuidv4(),
      action: 'AUDIT_VERIFICATION',
      resourceType: 'audit_log',
      actorId: req.user?.id,
      verificationResult: verification,
      entriesChecked: entries.length,
      priority: 'high'
    });

    res.json(verification);
  }
);

// Graceful shutdown - ensure all audits are flushed
process.on('SIGTERM', async () => {
  console.log('Flushing audit queue before shutdown...');
  await auditQueue.flush();
  await producer.disconnect();
  process.exit(0);
});

function sanitizeForAudit(data) {
  if (!data) return null;
  const sanitized = { ...data };
  const sensitiveFields = ['password', 'ssn', 'creditCard', 'apiKey', 'secret'];
  sensitiveFields.forEach(field => {
    if (sanitized[field]) sanitized[field] = '[REDACTED]';
  });
  return sanitized;
}
```

**Defense in Depth Layers**:

1. **Tamper-Evident Hash Chain**:
```javascript
// Each entry contains hash of previous entry
// Breaking the chain is cryptographically detectable
entry.previousHash = this.lastHash;
entry.hash = crypto.createHash('sha256').update(entryString).digest('hex');
```

2. **Digital Signatures for Non-Repudiation**:
```javascript
// Server signs each entry with private key
// Proves entry was created by authorized server
const sign = crypto.createSign('RSA-SHA256');
sign.update(entryString);
entry.signature = sign.sign(process.env.AUDIT_PRIVATE_KEY, 'base64');
```

3. **Multi-Destination Redundancy**:
```javascript
// Write to multiple systems simultaneously
// Attacker must compromise all to hide activity
await Promise.all([kafka, redis, writeAheadLog]);
```

**Additional Protections**:
- **Async Queue**: Non-blocking writes maintain API performance even under heavy audit load
- **Batch Correlation**: batchId links all entries from bulk operations for forensic reconstruction
- **Pre/Post Access Logging**: Sensitive data access logged before AND after retrieval
- **Data Fingerprinting**: SHA-256 hash of accessed data without storing PII in logs
- **Graceful Shutdown**: SIGTERM handler ensures all pending audits are flushed before exit
- **Write-Ahead Log**: Crash recovery mechanism prevents audit loss during failures
- **Access Justification**: Headers can require business justification for sensitive data access

No, modifying user roles without audit logging is a critical security failure. Without audit trails, you cannot detect unauthorized privilege escalation, investigate security incidents, or maintain compliance with regulations like SOX, GDPR, or HIPAA.

**VULNERABLE CODE**:

```java
import java.sql.*;
import javax.servlet.http.*;

public class UserRoleService {
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    public boolean updateUserRole(int userId, String newRole, HttpServletRequest request) {
        String sql = "UPDATE users SET role = ? WHERE id = ?";

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS);
             PreparedStatement stmt = conn.prepareStatement(sql)) {

            stmt.setString(1, newRole);
            stmt.setInt(2, userId);
            int rowsAffected = stmt.executeUpdate();

            // No logging of who changed what, when, or why
            return rowsAffected > 0;

        } catch (SQLException e) {
            // Silent failure - no logging
            return false;
        }
    }

    public boolean deleteUser(int userId) {
        String sql = "DELETE FROM users WHERE id = ?";

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS);
             PreparedStatement stmt = conn.prepareStatement(sql)) {

            stmt.setInt(1, userId);
            return stmt.executeUpdate() > 0;
            // Critical action with zero audit trail

        } catch (SQLException e) {
            return false;
        }
    }
}
```

**Attack Scenario**:
```text
1. Attacker compromises low-privilege account
2. Exploits vulnerability to escalate to admin role
3. Creates backdoor admin accounts
4. Deletes evidence and original compromised account
5. Without audit logs, breach goes undetected for months
```

**Why This Is Dangerous**:
- No record of who performed sensitive actions
- Privilege escalation attacks are undetectable
- Impossible to perform forensic analysis after a breach
- Regulatory compliance violations (SOX, HIPAA, PCI-DSS require audit trails)
- Insider threats cannot be identified or investigated

**SECURE VERSION**:

```java
import java.sql.*;
import java.time.Instant;
import java.util.UUID;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;

public class SecureUserRoleService {
    private static final Logger auditLog = LoggerFactory.getLogger("AUDIT");
    private static final Logger appLog = LoggerFactory.getLogger(SecureUserRoleService.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    public boolean updateUserRole(int targetUserId, String newRole, 
                                   HttpServletRequest request, int actorUserId) {
        String correlationId = UUID.randomUUID().toString();
        MDC.put("correlationId", correlationId);
        MDC.put("actorUserId", String.valueOf(actorUserId));

        String oldRole = null;

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // First, get the current role for audit purposes
            String selectSql = "SELECT role, username FROM users WHERE id = ?";
            try (PreparedStatement selectStmt = conn.prepareStatement(selectSql)) {
                selectStmt.setInt(1, targetUserId);
                ResultSet rs = selectStmt.executeQuery();
                if (rs.next()) {
                    oldRole = rs.getString("role");
                }
            }

            // Perform the update
            String updateSql = "UPDATE users SET role = ?, updated_at = ?, updated_by = ? WHERE id = ?";
            try (PreparedStatement updateStmt = conn.prepareStatement(updateSql)) {
                updateStmt.setString(1, newRole);
                updateStmt.setTimestamp(2, Timestamp.from(Instant.now()));
                updateStmt.setInt(3, actorUserId);
                updateStmt.setInt(4, targetUserId);

                int rowsAffected = updateStmt.executeUpdate();

                // Comprehensive audit log entry
                auditLog.info("ROLE_CHANGE event=ROLE_UPDATE targetUserId={} oldRole={} newRole={} " +
                             "actorUserId={} actorIp={} userAgent={} timestamp={} success={}",
                    targetUserId, oldRole, newRole, actorUserId,
                    request.getRemoteAddr(), 
                    request.getHeader("User-Agent"),
                    Instant.now().toString(),
                    rowsAffected > 0);

                // Also write to database audit table for tamper-evident storage
                writeAuditRecord(conn, "ROLE_UPDATE", actorUserId, targetUserId, 
                                oldRole, newRole, request.getRemoteAddr());

                return rowsAffected > 0;
            }
        } catch (SQLException e) {
            appLog.error("Database error during role update: targetUserId={}", targetUserId, e);
            auditLog.warn("ROLE_CHANGE event=ROLE_UPDATE_FAILED targetUserId={} actorUserId={} error={}",
                targetUserId, actorUserId, e.getMessage());
            return false;
        } finally {
            MDC.clear();
        }
    }

    private void writeAuditRecord(Connection conn, String action, int actorId, 
                                   int targetId, String oldValue, String newValue, String ipAddress) 
                                   throws SQLException {
        String sql = "INSERT INTO audit_log (action, actor_id, target_id, old_value, new_value, " +
                    "ip_address, created_at) VALUES (?, ?, ?, ?, ?, ?, ?)";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, action);
            stmt.setInt(2, actorId);
            stmt.setInt(3, targetId);
            stmt.setString(4, oldValue);
            stmt.setString(5, newValue);
            stmt.setString(6, ipAddress);
            stmt.setTimestamp(7, Timestamp.from(Instant.now()));
            stmt.executeUpdate();
        }
    }
}
```

**Key Security Controls**:
- **Before/After State Capture**: Records the previous role before modification for complete change tracking
- **Actor Attribution**: Every action is tied to the authenticated user who performed it
- **Dual Logging Strategy**: Both structured log files and database audit table for defense in depth
- **Contextual Information**: IP address, user agent, and timestamps enable forensic reconstruction

Excellent question. Tamper-evident audit logging is critical because sophisticated attackers will attempt to cover their tracks. You need multiple layers: cryptographic integrity verification, append-only storage, real-time external replication, and blockchain-style hash chaining.

**PRODUCTION PATTERN**:

```java
import java.security.*;
import java.sql.*;
import java.time.Instant;
import java.util.Base64;
import java.util.concurrent.*;
import javax.crypto.*;
import javax.crypto.spec.SecretKeySpec;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class TamperEvidentAuditService {
    private static final Logger auditLog = LoggerFactory.getLogger("SECURE_AUDIT");
    private static final Logger appLog = LoggerFactory.getLogger(TamperEvidentAuditService.class);

    private final ExecutorService asyncLogShipper;
    private final ExternalLogService externalLogService;
    private final String hmacKey;
    private String previousHash = "GENESIS";
    private final Object hashChainLock = new Object();

    public TamperEvidentAuditService(String hmacSecretKey, ExternalLogService externalService) {
        this.hmacKey = hmacSecretKey;
        this.externalLogService = externalService;
        this.asyncLogShipper = Executors.newFixedThreadPool(3);

        // Initialize hash chain from last known good state
        this.previousHash = loadLastHashFromSecureStorage();
    }

    public AuditRecord createTamperEvidentAuditRecord(
            String eventType,
            int actorId,
            int targetId,
            String action,
            String oldValue,
            String newValue,
            String ipAddress,
            String sessionId) {

        Instant timestamp = Instant.now();
        long sequenceNumber = getNextSequenceNumber();

        // Build canonical audit record
        AuditRecord record = new AuditRecord();
        record.setSequenceNumber(sequenceNumber);
        record.setTimestamp(timestamp);
        record.setEventType(eventType);
        record.setActorId(actorId);
        record.setTargetId(targetId);
        record.setAction(action);
        record.setOldValue(oldValue);
        record.setNewValue(newValue);
        record.setIpAddress(ipAddress);
        record.setSessionId(sessionId);

        // Create hash chain entry (blockchain-style)
        synchronized (hashChainLock) {
            String recordData = buildCanonicalString(record);
            String currentHash = computeChainedHash(previousHash, recordData);
            record.setPreviousHash(previousHash);
            record.setRecordHash(currentHash);
            previousHash = currentHash;
        }

        // Compute HMAC for integrity verification
        String hmacSignature = computeHMAC(record);
        record.setHmacSignature(hmacSignature);

        // Multi-destination logging (defense in depth)
        persistLocally(record);
        shipToExternalSIEM(record);
        writeToImmutableStorage(record);

        return record;
    }

    private String computeChainedHash(String previousHash, String currentData) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            String combined = previousHash + "|" + currentData;
            byte[] hash = digest.digest(combined.getBytes());
            return Base64.getEncoder().encodeToString(hash);
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("SHA-256 not available", e);
        }
    }

    private String computeHMAC(AuditRecord record) {
        try {
            Mac hmac = Mac.getInstance("HmacSHA256");
            SecretKeySpec keySpec = new SecretKeySpec(hmacKey.getBytes(), "HmacSHA256");
            hmac.init(keySpec);
            String data = buildCanonicalString(record);
            byte[] signature = hmac.doFinal(data.getBytes());
            return Base64.getEncoder().encodeToString(signature);
        } catch (Exception e) {
            appLog.error("HMAC computation failed", e);
