    public boolean verifyAuditChainIntegrity(long fromSequence, long toSequence) {
        // Verify the hash chain has not been tampered with
        try (Connection conn = getAuditDatabaseConnection()) {
            String sql = "SELECT * FROM immutable_audit_log WHERE sequence_number BETWEEN ? AND ? " +
                        "ORDER BY sequence_number ASC";

            try (PreparedStatement stmt = conn.prepareStatement(sql)) {
                stmt.setLong(1, fromSequence);
                stmt.setLong(2, toSequence);
                ResultSet rs = stmt.executeQuery();

                String expectedPreviousHash = null;
                while (rs.next()) {
                    String storedPreviousHash = rs.getString("previous_hash");
                    String storedRecordHash = rs.getString("record_hash");
                    String storedHmac = rs.getString("hmac_signature");

                    // Verify chain continuity
                    if (expectedPreviousHash != null && !expectedPreviousHash.equals(storedPreviousHash)) {
                        auditLog.error("CHAIN_INTEGRITY_VIOLATION seq={} expected={} found={}",
                            rs.getLong("sequence_number"), expectedPreviousHash, storedPreviousHash);
                        return false;
                    }

                    // Verify HMAC signature
                    AuditRecord reconstructed = reconstructFromResultSet(rs);
                    String computedHmac = computeHMAC(reconstructed);
                    if (!MessageDigest.isEqual(storedHmac.getBytes(), computedHmac.getBytes())) {
                        auditLog.error("HMAC_VERIFICATION_FAILED seq={}", rs.getLong("sequence_number"));
                        return false;
                    }

                    expectedPreviousHash = storedRecordHash;
                }
                return true;
            }
        } catch (SQLException e) {
            appLog.error("Chain verification failed", e);
            return false;
        }
    }

