        sessionId: req.session?.id,
        correlationId: req.headers['x-correlation-id']
      };

      auditLogger.info('ADMIN_ACTION', auditEntry);

      // Store in immutable audit table
      storeAuditRecord(pool, auditEntry);

      return originalJson(data);
