function sanitizeForLog(body) {
  const sanitized = { ...body };
  const sensitiveFields = ['password', 'token', 'secret', 'creditCard'];
  sensitiveFields.forEach(field => {
    if (sanitized[field]) {
      sanitized[field] = '[REDACTED]';
    }
  });
  return sanitized;
}

