class GDPRAuditService {
  constructor(auditLog, pool) {
    this.auditLog = auditLog;
    this.pool = pool;
  }

  // Determine retention period based on data type and jurisdiction
  getRetentionPeriod(action, targetType) {
    const retentionPolicies = {
      'FINANCIAL_TRANSACTION': 7 * 365, // 7 years for financial
      'SECURITY_EVENT': 5 * 365,        // 5 years for security
      'USER_DATA_ACCESS': 3 * 365,      // 3 years for data access
      'MARKETING_CONSENT': 6 * 365,     // 6 years for consent
      'DEFAULT': 2 * 365                 // 2 years default
    };

    const days = retentionPolicies[targetType] || retentionPolicies.DEFAULT;
    return new Date(Date.now() + (days * 24 * 60 * 60 * 1000));
  }

  // Log with GDPR compliance metadata
  async logWithCompliance(entry) {
    const complianceEntry = {
      ...entry,
      complianceTags: this.determineComplianceTags(entry),
      retentionUntil: this.getRetentionPeriod(entry.action, entry.targetType),
      legalBasis: entry.legalBasis || 'LEGITIMATE_INTEREST',
      dataCategories: this.classifyData(entry),
      processingPurpose: entry.purpose || 'SECURITY_MONITORING'
    };

    return this.auditLog.log(complianceEntry);
  }

  determineComplianceTags(entry) {
    const tags = [];
    if (entry.containsPersonalData) tags.push('GDPR');
    if (entry.financialData) tags.push('SOX', 'PCI-DSS');
    if (entry.healthData) tags.push('HIPAA');
    return tags;
  }

  classifyData(entry) {
    const categories = [];
    if (entry.targetEmail) categories.push('CONTACT_INFO');
    if (entry.action.includes('PASSWORD')) categories.push('CREDENTIALS');
    if (entry.action.includes('ROLE')) categories.push('ACCESS_RIGHTS');
    return categories;
  }

  // Data subject access request (DSAR) - export all audit logs for a user
  async handleDataSubjectRequest(userEmail) {
    const auditRecords = await this.pool.query(
      `SELECT audit_id, action, created_at, 
              target_resource, new_state
       FROM audit_log 
       WHERE target_email = $1 OR actor_email = $1
       ORDER BY created_at DESC`,
      [userEmail]
    );

    // Log the DSAR request itself
    await this.logWithCompliance({
      action: 'DSAR_EXPORT',
      targetEmail: userEmail,
      recordCount: auditRecords.rows.length,
      legalBasis: 'LEGAL_OBLIGATION'
    });

    return auditRecords.rows;
  }
}

