import javax.servlet.http.*;
import java.sql.*;
import java.time.Instant;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;

public class AdminSettingsController extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(AdminSettingsController.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");
    private static final String DB_URL = "jdbc:postgresql://localhost/appdb";
    private static final String DB_USER = "admin";
    private static final String DB_PASS = "password";

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String requestId = UUID.randomUUID().toString();
        MDC.put("requestId", requestId);

        String settingName = request.getParameter("setting");
        String settingValue = request.getParameter("value");
        String userId = (String) request.getSession().getAttribute("userId");
        String username = (String) request.getSession().getAttribute("username");
        String sourceIp = getClientIpAddress(request);
        String userAgent = request.getHeader("User-Agent");

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // Get the previous value for audit trail
            String previousValue = getPreviousValue(conn, settingName);

            // Update the setting
            String sql = "UPDATE system_settings SET value = ?, modified_by = ?, modified_at = ? WHERE name = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, settingValue);
            stmt.setString(2, userId);
            stmt.setTimestamp(3, Timestamp.from(Instant.now()));
            stmt.setString(4, settingName);
            int rowsAffected = stmt.executeUpdate();

            // Write comprehensive audit log
            AuditEvent event = new AuditEvent.Builder()
                .requestId(requestId)
                .timestamp(Instant.now())
                .eventType("ADMIN_SETTING_CHANGE")
                .action("UPDATE")
                .actorId(userId)
                .actorUsername(username)
                .sourceIp(sourceIp)
                .userAgent(userAgent)
                .resource("system_settings")
                .resourceId(settingName)
                .previousValue(previousValue)
                .newValue(settingValue)
                .outcome(rowsAffected > 0 ? "SUCCESS" : "NO_CHANGE")
                .build();

            writeAuditLog(event);
            persistAuditRecord(conn, event);

            response.setStatus(HttpServletResponse.SC_OK);
        } catch (SQLException e) {
            auditLogger.error("requestId={} action=ADMIN_SETTING_CHANGE outcome=FAILURE " +
                "actor={} setting={} error={}", requestId, userId, settingName, e.getMessage());
            response.setStatus(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
        } finally {
            MDC.clear();
        }
    }

    private String getPreviousValue(Connection conn, String settingName) throws SQLException {
        String sql = "SELECT value FROM system_settings WHERE name = ?";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, settingName);
            ResultSet rs = stmt.executeQuery();
            return rs.next() ? rs.getString("value") : null;
        }
    }

    private String getClientIpAddress(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private void writeAuditLog(AuditEvent event) {
        auditLogger.info("requestId={} timestamp={} eventType={} action={} actorId={} " +
            "actorUsername={} sourceIp={} resource={} resourceId={} previousValue={} " +
            "newValue={} outcome={}",
            event.getRequestId(), event.getTimestamp(), event.getEventType(),
            event.getAction(), event.getActorId(), event.getActorUsername(),
            event.getSourceIp(), event.getResource(), event.getResourceId(),
            event.getPreviousValue(), event.getNewValue(), event.getOutcome());
    }

    private void persistAuditRecord(Connection conn, AuditEvent event) throws SQLException {
        String sql = "INSERT INTO audit_log (request_id, timestamp, event_type, action, " +
            "actor_id, actor_username, source_ip, user_agent, resource, resource_id, " +
            "previous_value, new_value, outcome) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, event.getRequestId());
            stmt.setTimestamp(2, Timestamp.from(event.getTimestamp()));
            stmt.setString(3, event.getEventType());
            stmt.setString(4, event.getAction());
            stmt.setString(5, event.getActorId());
            stmt.setString(6, event.getActorUsername());
            stmt.setString(7, event.getSourceIp());
            stmt.setString(8, event.getUserAgent());
            stmt.setString(9, event.getResource());
            stmt.setString(10, event.getResourceId());
            stmt.setString(11, event.getPreviousValue());
            stmt.setString(12, event.getNewValue());
            stmt.setString(13, event.getOutcome());
            stmt.executeUpdate();
        }
    }
}
