import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import com.fasterxml.jackson.databind.ObjectMapper;

public class SecureAuditService {
    private static final Logger logger = LoggerFactory.getLogger(SecureAuditService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");
    private static final ObjectMapper objectMapper = new ObjectMapper();

    // Async processing for high-volume environments
    private final ExecutorService auditExecutor;
    private final BlockingQueue<AuditEvent> auditQueue;
    private final AuditPersistence persistence;
    private final AuditIntegrityService integrityService;
    private final AlertService alertService;

    // Configuration
    private static final int QUEUE_CAPACITY = 10000;
    private static final int BATCH_SIZE = 100;
    private static final long FLUSH_INTERVAL_MS = 1000;

    public SecureAuditService(DataSource dataSource, AlertService alertService) {
        this.auditQueue = new LinkedBlockingQueue<>(QUEUE_CAPACITY);
        this.auditExecutor = Executors.newFixedThreadPool(2);
        this.persistence = new AuditPersistence(dataSource);
        this.integrityService = new AuditIntegrityService();
        this.alertService = alertService;

        // Start background processors
        auditExecutor.submit(this::processAuditQueue);
        auditExecutor.submit(this::batchFlushProcessor);
    }

    /**
     * Non-blocking audit logging - returns immediately
     * Critical events bypass queue and log synchronously
     */
    public void logAuditEvent(AuditEvent event) {
        // Add integrity chain
        String previousHash = integrityService.getLastHash();
        event.setPreviousEventHash(previousHash);
        event.setEventHash(calculateEventHash(event, previousHash));
        integrityService.updateLastHash(event.getEventHash());

        // Critical security events get synchronous logging
        if (isCriticalSecurityEvent(event)) {
            logSynchronously(event);
            checkForAnomalies(event);
            return;
        }

        // Non-critical events use async queue
        boolean queued = auditQueue.offer(event);
        if (!queued) {
            // Queue full - log warning and process synchronously
            logger.warn("Audit queue full, processing synchronously: {}", event.getRequestId());
            logSynchronously(event);
            alertService.sendAlert("AUDIT_QUEUE_FULL", "Audit queue capacity reached");
        }
    }

    private boolean isCriticalSecurityEvent(AuditEvent event) {
        return event.getEventType().matches(
            "AUTH_FAILURE|PRIVILEGE_ESCALATION|SECURITY_SETTING_CHANGE|" +
            "USER_ROLE_CHANGE|DATA_EXPORT|MASS_DELETE|CONFIG_CHANGE");
    }

    private void logSynchronously(AuditEvent event) {
        // Write to multiple destinations for redundancy
        writeToLogFile(event);
        writeToDatabase(event);
        writeToSIEM(event);
    }

    private void writeToLogFile(AuditEvent event) {
        try {
            String jsonEvent = objectMapper.writeValueAsString(event);
            auditLogger.info(jsonEvent);
        } catch (Exception e) {
            logger.error("Failed to serialize audit event: {}", event.getRequestId(), e);
        }
    }

    private void writeToDatabase(AuditEvent event) {
        try {
            persistence.insertAuditRecord(event);
        } catch (Exception e) {
            logger.error("Failed to persist audit event: {}", event.getRequestId(), e);
            // Write to backup file for later recovery
            writeToBackupFile(event);
        }
    }

    private void writeToSIEM(AuditEvent event) {
        // Send to external SIEM (Splunk, ELK, etc.) for tamper-proof storage
        try {
            SIEMClient.getInstance().send(event);
        } catch (Exception e) {
            logger.error("Failed to send to SIEM: {}", event.getRequestId(), e);
        }
    }

    /**
     * Hash chain for tamper detection
     * Each event's hash includes the previous event's hash
     */
    private String calculateEventHash(AuditEvent event, String previousHash) {
        try {
            String data = String.format("%s|%s|%s|%s|%s|%s|%s|%s",
                previousHash,
                event.getRequestId(),
                event.getTimestamp().toString(),
                event.getEventType(),
                event.getActorId(),
                event.getResource(),
                event.getPreviousValue(),
                event.getNewValue());

            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(data.getBytes(StandardCharsets.UTF_8));
            return bytesToHex(hash);
        } catch (Exception e) {
            throw new RuntimeException("Failed to calculate event hash", e);
        }
    }

    private String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }

    /**
     * Real-time anomaly detection for security events
     */
    private void checkForAnomalies(AuditEvent event) {
        // Check for suspicious patterns
        if ("AUTH_FAILURE".equals(event.getEventType())) {
            int recentFailures = persistence.countRecentEvents(
                "AUTH_FAILURE", event.getSourceIp(), 5, TimeUnit.MINUTES);
            if (recentFailures >= 5) {
                alertService.sendCriticalAlert("BRUTE_FORCE_DETECTED",
                    String.format("5+ auth failures from %s in 5 minutes", event.getSourceIp()));
            }
        }

        // Check for privilege escalation
        if ("USER_ROLE_CHANGE".equals(event.getEventType())) {
            if (event.getNewValue().contains("ADMIN")) {
                alertService.sendCriticalAlert("PRIVILEGE_ESCALATION",
                    String.format("User %s granted admin role by %s",
                        event.getResourceId(), event.getActorUsername()));
            }
        }

        // Check for off-hours activity
        if (isOutsideBusinessHours(event.getTimestamp())) {
            if (isSensitiveOperation(event)) {
                alertService.sendAlert("OFF_HOURS_SENSITIVE_OPERATION",
                    String.format("%s performed by %s at %s",
                        event.getEventType(), event.getActorUsername(), event.getTimestamp()));
            }
        }
    }

    /**
     * Background processor for async queue
     */
    private void processAuditQueue() {
        while (!Thread.currentThread().isInterrupted()) {
            try {
                AuditEvent event = auditQueue.poll(100, TimeUnit.MILLISECONDS);
                if (event != null) {
                    logSynchronously(event);
                }
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                break;
            }
        }
    }

    /**
     * Periodic integrity verification
     */
    public boolean verifyAuditLogIntegrity(Instant from, Instant to) {
        List<AuditEvent> events = persistence.getEventsBetween(from, to);
        String expectedPreviousHash = null;

        for (AuditEvent event : events) {
            if (expectedPreviousHash != null && 
                !expectedPreviousHash.equals(event.getPreviousEventHash())) {
                logger.error("Audit log integrity violation detected at event: {}", 
                    event.getRequestId());
                alertService.sendCriticalAlert("AUDIT_LOG_TAMPERING",
                    "Hash chain broken at event " + event.getRequestId());
                return false;
            }

            String calculatedHash = calculateEventHash(event, event.getPreviousEventHash());
            if (!calculatedHash.equals(event.getEventHash())) {
                logger.error("Audit event hash mismatch: {}", event.getRequestId());
                alertService.sendCriticalAlert("AUDIT_LOG_TAMPERING",
                    "Event hash mismatch at " + event.getRequestId());
                return false;
            }

            expectedPreviousHash = event.getEventHash();
        }

        logger.info("Audit log integrity verified for {} events", events.size());
        return true;
    }

    private boolean isOutsideBusinessHours(Instant timestamp) {
        // Implementation to check business hours
        return false;
    }

    private boolean isSensitiveOperation(AuditEvent event) {
        return event.getEventType().matches(
            "CONFIG_CHANGE|USER_ROLE_CHANGE|DATA_EXPORT|SECURITY_SETTING_CHANGE");
    }

    private void writeToBackupFile(AuditEvent event) {
        // Write to local backup file for disaster recovery
    }

    private void batchFlushProcessor() {
