**Additional Protections**:

- **Database-Level Protection**: Use `INSERT`-only permissions for audit tables; no `UPDATE` or `DELETE`
- **Log Shipping**: Real-time replication to geographically separate write-once storage
- **Scheduled Integrity Checks**: Run `verifyAuditLogIntegrity()` hourly via cron
- **Retention Policies**: Minimum 1-year retention with legal hold capability
- **Access Monitoring**: Alert when anyone queries audit tables directly
- **Time Synchronization**: NTP to ensure accurate, synchronized timestamps across systems
- **Structured Logging**: JSON format enables automated parsing and analysis

Detecting anomalous access patterns requires real-time monitoring of audit logs with behavioral analysis. This is how you catch insider threats before mass data exfiltration occurs.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/google/uuid"
	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promauto"
	"go.uber.org/zap"
)

var (
	db          *sql.DB
	auditLogger *zap.Logger
	alertLogger *zap.Logger
)

// Prometheus metrics for security monitoring
var (
	dataAccessCounter = promauto.NewCounterVec(
		prometheus.CounterOpts{
			Name: "data_access_total",
			Help: "Total data access events by user and resource",
		},
		[]string{"user_id", "resource", "action"},
	)

	bulkAccessGauge = promauto.NewGaugeVec(
		prometheus.GaugeOpts{
			Name: "bulk_access_records",
			Help: "Number of records accessed in bulk operations",
		},
		[]string{"user_id", "resource"},
	)

	securityAlertsCounter = promauto.NewCounterVec(
		prometheus.CounterOpts{
			Name: "security_alerts_total",
			Help: "Security alerts triggered",
		},
		[]string{"alert_type", "severity"},
	)
)

// UserAccessProfile tracks normal behavior patterns
type UserAccessProfile struct {
	UserID              string
	TypicalAccessHours  []int // Hours 0-23 when user normally works
	AvgDailyRecords     int
	MaxSingleExport     int
	TypicalResources    map[string]bool
	LastAccessTime      time.Time
	AccessCountToday    int
	RecordsAccessedToday int
	mu                  sync.RWMutex
}

var userProfiles = make(map[string]*UserAccessProfile)
var profileMu sync.RWMutex

// AnomalyDetector checks for suspicious patterns
type AnomalyDetector struct {
	// Thresholds - configurable per environment
	MaxRecordsPerRequest    int
	MaxRecordsPerHour       int
	MaxRecordsPerDay        int
	AllowedAccessHours      map[int]bool
	SensitiveFieldsAccessed int
	AlertThreshold          float64
}

func NewAnomalyDetector() *AnomalyDetector {
	return &AnomalyDetector{
		MaxRecordsPerRequest: 100,
		MaxRecordsPerHour:    500,
		MaxRecordsPerDay:     2000,
		AllowedAccessHours:   map[int]bool{8: true, 9: true, 10: true, 11: true, 12: true, 13: true, 14: true, 15: true, 16: true, 17: true, 18: true},
		AlertThreshold:       2.0, // Standard deviations from normal
	}
}

type SecurityAlert struct {
	AlertID     string    `json:"alert_id"`
	Timestamp   time.Time `json:"timestamp"`
	Severity    string    `json:"severity"`
	AlertType   string    `json:"alert_type"`
	UserID      string    `json:"user_id"`
	Description string    `json:"description"`
	Context     map[string]interface{} `json:"context"`
	RecommendedAction string `json:"recommended_action"`
}

var anomalyDetector = NewAnomalyDetector()

func (ad *AnomalyDetector) CheckAccess(ctx context.Context, event AuditEvent) []SecurityAlert {
	var alerts []SecurityAlert

	// Get or create user profile
	profileMu.Lock()
	profile, exists := userProfiles[event.UserID]
	if !exists {
		profile = &UserAccessProfile{
			UserID:           event.UserID,
			TypicalResources: make(map[string]bool),
		}
		userProfiles[event.UserID] = profile
	}
	profileMu.Unlock()

	profile.mu.Lock()
	defer profile.mu.Unlock()

	now := time.Now()
	currentHour := now.Hour()

	// CHECK 1: Bulk data access
	if event.RecordCount > ad.MaxRecordsPerRequest {
		alerts = append(alerts, SecurityAlert{
			AlertID:     uuid.New().String(),
			Timestamp:   now,
			Severity:    "HIGH",
			AlertType:   "BULK_DATA_ACCESS",
			UserID:      event.UserID,
			Description: fmt.Sprintf("User accessed %d records in single request (threshold: %d)", event.RecordCount, ad.MaxRecordsPerRequest),
			Context: map[string]interface{}{
				"record_count": event.RecordCount,
				"resource":     event.Resource,
				"ip_address":   event.IPAddress,
			},
			RecommendedAction: "Review user session, consider temporary access suspension",
		})
	}

	// CHECK 2: After-hours access
	if !ad.AllowedAccessHours[currentHour] {
		alerts = append(alerts, SecurityAlert{
			AlertID:     uuid.New().String(),
			Timestamp:   now,
			Severity:    "MEDIUM",
			AlertType:   "AFTER_HOURS_ACCESS",
			UserID:      event.UserID,
			Description: fmt.Sprintf("Data access at unusual hour: %d:00", currentHour),
			Context: map[string]interface{}{
				"access_hour": currentHour,
				"resource":    event.Resource,
				"ip_address":  event.IPAddress,
			},
			RecommendedAction: "Verify with user, check for compromised credentials",
		})
	}

	// CHECK 3: Velocity anomaly - too many records today
	if now.Day() == profile.LastAccessTime.Day() {
		profile.RecordsAccessedToday += event.RecordCount
		profile.AccessCountToday++
	} else {
		// New day - reset counters
		profile.RecordsAccessedToday = event.RecordCount
		profile.AccessCountToday = 1
	}

	if profile.RecordsAccessedToday > ad.MaxRecordsPerDay {
		alerts = append(alerts, SecurityAlert{
			AlertID:     uuid.New().String(),
			Timestamp:   now,
			Severity:    "CRITICAL",
			AlertType:   "EXCESSIVE_DATA_ACCESS",
			UserID:      event.UserID,
			Description: fmt.Sprintf("User accessed %d records today (threshold: %d)", profile.RecordsAccessedToday, ad.MaxRecordsPerDay),
			Context: map[string]interface{}{
				"daily_records":   profile.RecordsAccessedToday,
				"daily_requests":  profile.AccessCountToday,
				"threshold":       ad.MaxRecordsPerDay,
			},
			RecommendedAction: "Immediate session termination and security review",
		})
	}

	// CHECK 4: Sensitive field access pattern
	hasSensitiveFields := containsSensitiveFields(event.DataFields)
	if hasSensitiveFields && event.RecordCount > 10 {
		alerts = append(alerts, SecurityAlert{
			AlertID:     uuid.New().String(),
			Timestamp:   now,
			Severity:    "HIGH",
			AlertType:   "SENSITIVE_BULK_ACCESS",
			UserID:      event.UserID,
			Description: fmt.Sprintf("Bulk access to sensitive fields: %v", event.DataFields),
			Context: map[string]interface{}{
				"fields":       event.DataFields,
				"record_count": event.RecordCount,
			},
			RecommendedAction: "Escalate to security team immediately",
		})
	}

	// CHECK 5: New resource access (first time accessing this type of data)
	if !profile.TypicalResources[event.Resource] {
		if len(profile.TypicalResources) > 5 { // User has established pattern
			alerts = append(alerts, SecurityAlert{
				AlertID:     uuid.New().String(),
				Timestamp:   now,
				Severity:    "LOW",
				AlertType:   "NEW_RESOURCE_ACCESS",
				UserID:      event.UserID,
				Description: fmt.Sprintf("First-time access to resource: %s", event.Resource),
				Context: map[string]interface{}{
					"new_resource":     event.Resource,
					"typical_resources": profile.TypicalResources,
				},
				RecommendedAction: "Monitor for additional anomalous behavior",
			})
		}
		profile.TypicalResources[event.Resource] = true
	}

	profile.LastAccessTime = now

	// Process alerts
	for _, alert := range alerts {
		processSecurityAlert(ctx, alert)
	}

	return alerts
}

func containsSensitiveFields(fields []string) bool {
	sensitive := map[string]bool{"ssn": true, "password": true, "credit_card": true, "dob": true, "salary": true}
	for _, f := range fields {
		if sensitive[f] {
			return true
		}
	}
	return false
}

func processSecurityAlert(ctx context.Context, alert SecurityAlert) {
	// Log to security alert stream
	alertLogger.Warn("SECURITY_ALERT",
		zap.String("alert_id", alert.AlertID),
		zap.String("severity", alert.Severity),
		zap.String("alert_type", alert.AlertType),
		zap.String("user_id", alert.UserID),
		zap.String("description", alert.Description),
		zap.Any("context", alert.Context),
	)

	// Update Prometheus metrics
	securityAlertsCounter.WithLabelValues(alert.AlertType, alert.Severity).Inc()

	// CRITICAL alerts trigger immediate action
	if alert.Severity == "CRITICAL" {
		// Send to SIEM/SOC
		sendToSOC(alert)

		// Optionally terminate user session
		terminateUserSession(ctx, alert.UserID)
	}

	// Persist alert for investigation
	_, _ = db.ExecContext(ctx,
		`INSERT INTO security_alerts (alert_id, timestamp, severity, alert_type, user_id, description, context, status)
		 VALUES ($1, $2, $3, $4, $5, $6, $7, 'OPEN')`,
		alert.AlertID, alert.Timestamp, alert.Severity, alert.AlertType,
		alert.UserID, alert.Description, alert.Context,
	)
}

func sendToSOC(alert SecurityAlert) {
	// Integration with SIEM (Splunk, Sentinel, etc.)
	alertJSON, _ := json.Marshal(alert)
	// Send to webhook, message queue, etc.
	fmt.Printf("SOC ALERT: %s\n", alertJSON)
}

func terminateUserSession(ctx context.Context, userID string) {
	// Invalidate all sessions for user
	_, _ = db.ExecContext(ctx, "UPDATE sessions SET revoked = true WHERE user_id = $1", userID)
}

// Enhanced export endpoint with anomaly detection
func exportUsers(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()
	authUser := ctx.Value("auth_user").(string)
	sessionID := ctx.Value("session_id").(string)

	// Count records first
	var recordCount int
	db.QueryRowContext(ctx, "SELECT COUNT(*) FROM users").Scan(&recordCount)

	auditEvent := AuditEvent{
		UserID:      authUser,
		SessionID:   sessionID,
		Action:      "EXPORT",
		Resource:    "users",
		ResourceID:  "all",
		IPAddress:   r.RemoteAddr,
		UserAgent:   r.UserAgent(),
		DataFields:  []string{"id", "name", "email", "ssn"},
		RecordCount: recordCount,
	}

	// Run anomaly detection BEFORE allowing access
	alerts := anomalyDetector.CheckAccess(ctx, auditEvent)

	// Block if critical alert
	for _, alert := range alerts {
		if alert.Severity == "CRITICAL" {
			auditEvent.Result = "BLOCKED_ANOMALY"
			logAuditEvent(ctx, auditEvent)
			http.Error(w, "Access denied - security review required", http.StatusForbidden)
			return
		}
	}

	// Proceed with export
	rows, err := db.QueryContext(ctx, "SELECT id, name, email FROM users") // Note: SSN excluded from bulk export
	if err != nil {
		auditEvent.Result = "ERROR"
		logAuditEvent(ctx, auditEvent)
		http.Error(w, "Export failed", http.StatusInternalServerError)
		return
	}
	defer rows.Close()

	auditEvent.Result = "SUCCESS"
	logAuditEvent(ctx, auditEvent)

	// Update metrics
	dataAccessCounter.WithLabelValues(authUser, "users", "EXPORT").Inc()
	bulkAccessGauge.WithLabelValues(authUser, "users").Set(float64(recordCount))

	// Stream response
	var users []User
	for rows.Next() {
		var u User
		rows.Scan(&u.ID, &u.Name, &u.Email)
		users = append(users, u)
	}

	json.NewEncoder(w).Encode(users)
}
