let lastEventHash = 'GENESIS';

function createEventHash(event) {
  const eventString = JSON.stringify(event) + lastEventHash;
  const hash = crypto.createHash('sha256').update(eventString).digest('hex');
  lastEventHash = hash;
  return hash;
}

// Comprehensive audit logging class
class AuditTrail {
  static log(eventType, req, details = {}, outcome = 'SUCCESS') {
    const event = {
      eventId: uuidv4(),
      eventType: eventType,
      timestamp: new Date().toISOString(),
      outcome: outcome,
      actor: {
        userId: req.user?.id || null,
        username: req.user?.username || null,
        email: req.user?.email || null,
        role: req.user?.role || null,
        accountType: req.user?.accountType || null
      },
      source: {
        ipAddress: req.ip || req.headers['x-forwarded-for']?.split(',')[0],
        userAgent: req.headers['user-agent'],
        origin: req.headers['origin'],
        sessionId: req.sessionID || null,
        correlationId: req.correlationId
      },
      request: {
        method: req.method,
        path: req.originalUrl,
        query: this.sanitizeData(req.query),
        contentLength: req.headers['content-length']
      },
      resource: details.resource || null,
      changes: details.changes || null,
      metadata: details.metadata || {},
      riskIndicators: this.calculateRiskIndicators(req, eventType, details)
    };

    // Add tamper-evident hash for critical events
    if (this.isCriticalEvent(eventType)) {
      event.integrityHash = createEventHash(event);
      event.previousHash = lastEventHash;
    }

    auditLogger.info(event);

    // Real-time alerting for high-risk events
    if (event.riskIndicators.riskScore >= 70) {
      this.triggerSecurityAlert(event);
    }

    return event.eventId;
  }

  static sanitizeData(data) {
    if (!data) return null;
    const sensitiveFields = ['password', 'token', 'secret', 'apiKey', 'ssn', 'creditCard'];
    const sanitized = { ...data };
    for (const field of sensitiveFields) {
      if (sanitized[field]) {
        sanitized[field] = '[REDACTED]';
      }
    }
    return sanitized;
  }

  static calculateRiskIndicators(req, eventType, details) {
    let riskScore = 0;
    const indicators = [];

    // Failed authentication attempts
    if (eventType === AuditEventTypes.AUTH_LOGIN_FAILURE) {
      riskScore += 20;
      indicators.push('FAILED_AUTH');
    }

    // Privilege escalation
    if (eventType === AuditEventTypes.ADMIN_PRIVILEGE_CHANGE) {
      riskScore += 40;
      indicators.push('PRIVILEGE_CHANGE');
    }

    // Bulk data export
    if (eventType === AuditEventTypes.DATA_EXPORT) {
      riskScore += 30;
      indicators.push('DATA_EXPORT');
    }

    // Unusual access time (outside business hours)
    const hour = new Date().getHours();
    if (hour < 6 || hour > 22) {
      riskScore += 15;
      indicators.push('OFF_HOURS_ACCESS');
    }

    // Access from new IP (would check against user's known IPs)
    if (details.metadata?.newIpAddress) {
      riskScore += 25;
      indicators.push('NEW_IP_ADDRESS');
    }

    return { riskScore, indicators };
  }

  static isCriticalEvent(eventType) {
    const criticalEvents = [
      AuditEventTypes.ADMIN_PRIVILEGE_CHANGE,
      AuditEventTypes.ADMIN_USER_DELETE,
      AuditEventTypes.DATA_EXPORT,
      AuditEventTypes.AUTH_PASSWORD_CHANGE
    ];
    return criticalEvents.includes(eventType);
  }

  static async triggerSecurityAlert(event) {
    // Send to security team via webhook/PagerDuty
    console.warn('SECURITY ALERT:', event.eventType, event.riskIndicators);
    // await securityWebhook.send(event);
  }
}

// Authentication endpoint with comprehensive logging
app.post('/api/auth/login', async (req, res) => {
  const { username, password } = req.body;

  try {
    const user = await db.findUserByUsername(username);

    if (!user) {
      AuditTrail.log(AuditEventTypes.AUTH_LOGIN_FAILURE, req, {
        metadata: { 
          reason: 'USER_NOT_FOUND',
          attemptedUsername: username 
        }
      }, 'FAILURE');
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const passwordValid = await verifyPassword(password, user.passwordHash);

    if (!passwordValid) {
      AuditTrail.log(AuditEventTypes.AUTH_LOGIN_FAILURE, req, {
        resource: { type: 'user', id: user.id },
        metadata: { reason: 'INVALID_PASSWORD' }
      }, 'FAILURE');

      // Track failed attempts for lockout
      await incrementFailedAttempts(user.id);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Successful login
    const token = generateToken(user);
    req.user = user;

    AuditTrail.log(AuditEventTypes.AUTH_LOGIN_SUCCESS, req, {
      resource: { type: 'user', id: user.id },
      metadata: { 
        loginMethod: 'password',
        mfaUsed: false,
        newIpAddress: await isNewIpForUser(user.id, req.ip)
      }
    });

    res.json({ token, user: { id: user.id, username: user.username } });

  } catch (error) {
    auditLogger.error({
      eventType: 'SYSTEM_ERROR',
      error: error.message,
      stack: error.stack,
      correlationId: req.correlationId
    });
    res.status(500).json({ error: 'Authentication service unavailable' });
  }
});

// Admin action with full audit trail
app.delete('/api/admin/users/:id', authenticate, authorize('admin'), async (req, res) => {
  const targetUserId = req.params.id;

  try {
    // Capture state before deletion
    const userToDelete = await db.getUserById(targetUserId);

    if (!userToDelete) {
      AuditTrail.log(AuditEventTypes.ADMIN_USER_DELETE, req, {
        resource: { type: 'user', id: targetUserId },
        metadata: { reason: 'USER_NOT_FOUND' }
      }, 'FAILURE');
      return res.status(404).json({ error: 'User not found' });
    }

    // Perform deletion
    await db.deleteUser(targetUserId);

    // Comprehensive audit log with before-state
    AuditTrail.log(AuditEventTypes.ADMIN_USER_DELETE, req, {
      resource: { type: 'user', id: targetUserId },
      changes: {
        before: {
          username: userToDelete.username,
          email: userToDelete.email,
          role: userToDelete.role,
          createdAt: userToDelete.createdAt
        },
        after: null
      },
      metadata: {
        deletedBy: req.user.id,
        deletionReason: req.body.reason || 'Not specified'
      }
    });

    res.json({ success: true, message: 'User deleted' });

  } catch (error) {
    AuditTrail.log(AuditEventTypes.ADMIN_USER_DELETE, req, {
      resource: { type: 'user', id: targetUserId },
      metadata: { error: error.message }
    }, 'ERROR');
    res.status(500).json({ error: 'Failed to delete user' });
  }
});

